const agentResponse = $json;
const ctx = $('Lookup & Parse Patient').item.json || $('Extract Data').item.json || {};

function extractText(res) {
  if (!res) return '';
  if (typeof res === 'string') return res;
  if (typeof res.output === 'string') return res.output;
  if (res.output?.text) return res.output.text;
  if (res.text)    return res.text;
  if (res.response) return res.response;
  if (res.message)  return res.message;
  return '';
}

let rawText = extractText(agentResponse).replace(/^json\s*\n?/i, '').trim();

const conversationId = ctx.conversationId || agentResponse.conversationId || '';
const chatInput      = ctx.chatInput      || agentResponse.chatInput      || '';
const sessionId      = ctx.sessionId      || agentResponse.sessionId      || '';

let intent = 'INFORMACAO', confidence = 0.5, unit = null,
    needsUnit = false, parsedResponse = null, reasoning = '';

const m = rawText.match(/\{[\s\S]*?\}/);
if (m) {
  try {
    const p = JSON.parse(m[0]);
    intent         = p.intent      || intent;
    confidence     = p.confidence  || confidence;
    reasoning      = p.reasoning   || '';
    unit           = p.unit        || null;
    needsUnit      = p.needsUnit   ?? false;
    parsedResponse = p.response    || null;
  } catch(_) {}
}

if (agentResponse.intent) {
  intent     = agentResponse.intent;
  confidence = agentResponse.confidence || confidence;
  unit       = agentResponse.unit || unit;
}

if (!unit && chatInput) {
  const lo = chatInput.toLowerCase();
  if (lo.includes('vieiralves'))                              unit = 'Vieiralves';
  else if (lo.includes('são josé') || lo.includes('sao jose')) unit = 'São José';
}

if (chatInput) {
  const lo = chatInput.toLowerCase();
  if (['agendar','marcar','reservar'].some(k => lo.includes(k)))         { intent = 'AGENDAR';         confidence = 0.9;  }
  else if (['atendente','humano','falar com'].some(k => lo.includes(k))) { intent = 'FALAR_ATENDENTE'; confidence = 0.95; }
}

const validIntents = ['INFORMACAO','AGENDAR','FALAR_ATENDENTE','PEDIR_UNIDADE'];
if (!validIntents.includes(intent)) intent = 'INFORMACAO';

if (!unit && (intent === 'AGENDAR' || intent === 'INFORMACAO')) {
  needsUnit = true;
  intent    = 'PEDIR_UNIDADE';
}

return [{
  json: {
    conversationId, sessionId, intent, confidence, reasoning, unit, needsUnit,
    response:        parsedResponse || rawText,
    chatInput,
    originalMessage: chatInput,
    phone:           ctx.phone     || '',
    platform:        ctx.platform  || 'whatsapp',
    needsPhone:      ctx.needsPhone|| false,
    patient:         ctx.patient   || {},
    patientFound:    ctx.patientFound || false,
    patientName:     ctx.patientName  || null,
    convenioId:      ctx.convenioId   || null,
    context:         ctx.context      || {},
    appointmentFlow: ctx.appointmentFlow || {
      patientChecked: false, patientData: null,
      insuranceValidated: false, step: 'initial'
    },
    messageReceivedAt: ctx.messageReceivedAt,
    success: true
  }
}];

const data = $json;

if (!data.conversationId) throw new Error('conversationId obrigatório');

let message = null;

if (data.response) {
  if (typeof data.response === 'string') {
    try {
      const parsed = JSON.parse(data.response);
      if (parsed.response) {
        message = parsed.response;
      }
    } catch (e) {
      message = data.response;
    }
  } else {
    message = data.response;
  }
}

if (!message && data.message) {
  message = data.message;
}

if (message && typeof message === 'string') {
  message = message.replace(/^json\s*\n?/i, '').trim();
  const backtick = String.fromCharCode(96);
  const codeBlockPattern = new RegExp('^' + backtick + backtick + backtick + 'json\\s*\\n?', 'i');
  message = message.replace(codeBlockPattern, '').trim();
  const codeBlockStart = new RegExp('^' + backtick + backtick + backtick + '\\s*\\n?', 'i');
  message = message.replace(codeBlockStart, '').trim();
  const codeBlockEnd = new RegExp(backtick + backtick + backtick + '\\s*$', 'i');
  message = message.replace(codeBlockEnd, '').trim();
}

if (!message || message.trim() === '') {
  message = 'Qual unidade você prefere?\n1 - Vieiralves\n2 - São José\n\nDigite o número da unidade desejada. 😊';
}

return [{
  json: {
    conversationId: data.conversationId,
    message: message,
    intent: data.intent || 'INFORMACAO',
    action: data.action || 'RESPOND',
    aiProvider: 'n8n-gemini',
    requiresHumanIntervention: data.requiresHumanIntervention || false,
    appointmentFlow: data.appointmentFlow || null,
    success: true,
    timestamp: new Date().toISOString()
  }
}];

